{
  "schemaVersion": 2,
  "id": "compact-workspace-pack",
  "name": "Compact Workspace Pack",
  "version": "1.0.0",
  "entry": null,
  "pluginType": "ui-snippet",
  "capabilities": ["theme.snippet"],
  "platforms": ["desktop", "web"],
  "requiresRestart": false,
  "experimental": false,
  "minAppVersion": "0.6.0",
  "maxAppVersion": null,
  "permissions": {
    "theme": {
      "register": true
    }
  },
  "contributes": {
    "theme": {
      "style": [],
      "snippets": [
        {
          "file": "theme/snippets/compact-sidebar-pack.css",
          "id": "compact-sidebar-pack",
          "label": "Compact Sidebar Pack",
          "description": "Tighter workspace sidebar rows for large vaults.",
          "defaultEnabled": true
        }
      ],
      "tokens": [],
      "defaultEnable": {
        "snippets": ["compact-sidebar-pack"]
      }
    },
    "commands": [],
    "preferencesSections": [],
    "panels": []
  }
}

/**
 * compact-sidebar-pack — plugin-bundled UI snippet
 *
 * Copy target: ~/.luna/theme/snippets/compact-sidebar-pack.css
 * Based on theme-example/snippets/compact-sidebar.css, scoped for plugin packaging.
 */

html[data-theme='light'],
html[data-theme='dark'] {
  --sidebar-row-height: 28px;
}

.sidebar .workspace-tree-node,
.sidebar .workspace-file-row,
.sidebar .workspace-folder-row {
  min-height: var(--sidebar-row-height);
}

.sidebar .workspace-tree-node {
  padding-top: 2px;
  padding-bottom: 2px;
}

.sidebar .workspace-tree-node .workspace-node-label {
  font-size: 12px;
}

.sidebar .workspace-tree-node .tree-icon {
  opacity: 0.68;
}
